class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int maxLen = 1;
        int lastSeen = -1;
        int pairIndex = -1;

        for (int i = 1; i < s.size(); ++i) {
            if (s[i] == s[i - 1]) {
                if (lastSeen != -1 && s[i] != s[lastSeen]) {
                    pairIndex = lastSeen;
                }
                lastSeen = i;
            }
            if (pairIndex != -1 && i - pairIndex > maxLen) {
                maxLen = i - pairIndex;
            }
            if (lastSeen != -1 && i - lastSeen > maxLen) {
                maxLen = i - lastSeen;
            }
        }
        return maxLen;
    }
};
